chrome.runtime.onInstalled.addListener(()=>{console.log("Resume Tailor extension installed")});chrome.runtime.onMessage.addListener((e,t)=>{var a,o;e.type==="JD_EXTRACTED"&&((a=t.tab)!=null&&a.id)&&(chrome.action.setBadgeText({text:"JD",tabId:t.tab.id}),chrome.action.setBadgeBackgroundColor({color:"#2563EB",tabId:t.tab.id})),e.type==="JD_NOT_FOUND"&&((o=t.tab)!=null&&o.id)&&chrome.action.setBadgeText({text:"",tabId:t.tab.id})});chrome.tabs.onUpdated.addListener((e,t)=>{t.status==="loading"&&chrome.action.setBadgeText({text:"",tabId:e})});
